import os
import yaml
from pathlib import Path

class Config:
    def __init__(self, project_dir):
        self.project_dir = project_dir
        self.config_file = os.path.join(project_dir, '.projcli', 'config.yaml')
        self.config_data = self.load_config()

    def load_config(self):
        with open(self.config_file, 'r') as f:
            return yaml.safe_load(f)

    def get_config(self, key):
        return self.config_data.get(key)

    def set_config(self, key, value):
        self.config_data[key] = value
        self.save_config()

    def save_config(self):
        with open(self.config_file, 'w') as f:
            yaml.safe_dump(self.config_data, f)
```

### 2. Create a Context Object

Next, create a context object that will hold the configuration and be passed to each command.

