import requests

class RESTAPICConnector(BaseConnector):
    def connect(self):
        pass  # REST APIs don't require explicit connection

    def fetch_data(self):
        response = requests.get(self.config['url'], headers=self.config.get('headers', {}))

        if response.status_code == 200:
            data = response.json()

