def handle_webhook_retry(webhook_config, retries=3):
    attempts = 0
    while attempts < retries:
        try:
            webhook_listener = EventWebhookListener(webhook_config)
            webhook_listener.connect()

            # Wait for the listener to start and then return
            time.sleep(1)  # Give some buffer time before returning

            return webhook_listener
        except Exception as e:
            logger.error(f"Failed to start webhook listener: {e}")

            # Exponential backoff with random jitter
            wait_time = (2 ** attempts) + randint(0, 1)
            time.sleep(wait_time)

            attempts += 1

    raise Exception("Max retries exceeded")

