import polars as pl

class BaseConnector:
    def __init__(self, config):
        self.config = config

    def connect(self):
        """Establishes the connection to the data source."""
        raise NotImplementedError("This method should be overridden by subclasses.")

    def fetch_data(self) -> pl.DataFrame:
        """Fetches data from the connected source and returns it as a Polars DataFrame."""
        raise NotImplementedError("This method should be overridden by subclasses.")

class CSVDirectoryConnector(BaseConnector):
    def connect(self):
        self.file_paths = glob(os.path.join(self.config.directory, '*.csv'))

    def fetch_data(self) -> pl.DataFrame:
        dfs = [pl.read_csv(file_path) for file_path in self.file_paths]

        return pl.concat(dfs, how="vertical") if dfs else None

class JSONDirectoryConnector(BaseConnector):
    def connect(self):
        self.file_paths = glob(os.path.join(self.config.directory, '*.json'))

    def fetch_data(self) -> pl.DataFrame:
        dfs = []

        for file_path in self.file_paths:
            with open(file_path, 'r') as f:
                data = json.load(f)

            # Convert JSON to DataFrame
            df = pl.DataFrame(data)

            dfs.append(df)

        return pl.concat(dfs) if dfs else None

class RESTAPICConnector(BaseConnector):
    def connect(self):
        pass  # REST APIs don't require explicit connection

    def fetch_data(self) -> pl.DataFrame:
        response = requests.get(self.config.url, headers=self.config.headers)

        if response.status_code == 200:
            data = response.json()

            # Convert JSON to DataFrame
            df = pl.DataFrame(data)

            return df
        else:
            raise Exception(f"Failed to fetch data from {self.config.url}")

class SchemaManager:
    def __init__(self, initial_schema):
        self.current_schema = set(initial_schema)

    def update_schema(self, new_columns):
        # Add new columns to the current schema if they don't exist already.
        for column in new_columns:
            if column not in self.current_schema:
                self.current_schema.add(column)

    def get_current_schema(self):
        return list(self.current_schema)

