### 3. **Update ETLOrchestrator Class**
Modify the `ETLOrchestrator` class to collect and expose these metrics during pipeline execution.

#### Updated ETLOrchestrator Class:
```python
import logging
from datetime import datetime
import pandas as pd
import requests
import json
from prometheus_client import Counter, Summary

# Setup logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def setup_logging():
    logger = logging.getLogger(__name__)
    return logger

logger = setup_logging()

# Define metrics
run_count = Counter('etl_runs_total', 'Total number of ETL runs')
success_run_count = Counter('etl_success_runs_total', 'Number of successful ETL runs')
job_duration_summary = Summary('etl_job_duration_seconds', 'Duration of ETL job in seconds')

class CSVExtractor:
    def __init__(self, file_path):
        self.file_path = file_path

    def extract_new_data(self):
        try:
            df = pd.read_csv(self.file_path)
            return df
        except Exception as e:
            logger.error(f"Failed to read CSV: {e}")
            raise

class JSONExtractor:
    def __init__(self, file_path):
        self.file_path = file_path

    def extract_new_data(self):
        try:
            with open(self.file_path) as f:
                data = json.load(f)
            return data
        except Exception as e:
            logger.error(f"Failed to read JSON: {e}")
            raise

class RESTAPIExtractor:
    def __init__(self, url, headers=None):
        self.url = url
        self.headers = headers

    def extract_new_data(self):
        try:
            response = requests.get(self.url, headers=self.headers)
            if response.status_code == 200:
                return response.json()
            else:
                logger.error(f"Failed to fetch data from {self.url}")
                raise Exception("API request failed")
        except Exception as e:
            logger.error(f"Failed to read API data: {e}")
            raise

class DataTransformer:
    def __init__(self):
        pass

    def transform(self, data):
        if isinstance(data, pd.DataFrame):
            return data.applymap(lambda x: x.lower() if type(x) == str else x).drop_duplicates()

        elif isinstance(data, dict):  # Assuming JSON is a dictionary
            return {k.lower(): v for k, v in data.items()}

        raise ValueError(f"Unsupported data type: {type(data)}")

class DataLoader:
    def __init__(self, db_path):
        self.conn = sqlite3.connect(db_path)

    def load(self, df):
        try:
            df.to_sql('data_table', con=self.conn, if_exists='replace')
        except Exception as e:
            logger.error(f"Failed to load data into database: {e}")
            raise

class PipelineRunMetadata:
    def __init__(self, run_id=None):
        self.run_id = run_id if run_id else str(datetime.now().timestamp())
        self.start_time = None
        self.end_time = None
        self.duration = 0
        self.status = 'success'
        self.error_message = ''
        self.records_processed = 0
        self.data_sources = []

    def start(self):
        self.start_time = datetime.now()

    def end(self, success=True, error_message=None):
        self.end_time = datetime.now()
        self.duration = (self.end_time - self.start_time).total_seconds()
        if not success:
            self.status = 'failure'
            self.error_message = str(error_message)

    def log_data_source(self, source_name, details):
        self.data_sources.append({
            "source": source_name,
            "details": details
        })

    def update_records_processed(self, records_count):
        self.records_processed += records_count

    def to_dict(self):
        return {
            "run_id": self.run_id,
            "start_time": self.start_time.isoformat(),
            "end_time": self.end_time.isoformat() if self.end_time else None,
            "duration": self.duration,
            "status": self.status,
            "error_message": self.error_message,
            "records_processed": self.records_processed,
            "data_sources": self.data_sources
        }

    def save_to_file(self, file_path):
        with open(file_path, 'w') as f:
            json.dump(self.to_dict(), f, indent=4)

class Metric:
    def __init__(self):
        self.name = None

    def collect(self):
        pass

    def store(self, metadata):
        pass


class RowCountMetric(Metric):
    def __init__(self):
        super().__init__()
        self.name = "RowCount"

    def collect(self, data_sources):
        records_processed = 0
        for source, data in data_sources:
            if isinstance(data, pd.DataFrame):
                records_processed += len(data.index)
            elif isinstance(data, dict) or isinstance(data, list):  # Assuming JSON or API response
                records_processed += len(data)
        return records_processed

    def store(self, metadata, value):
        metadata.update_records_processed(value)


class DurationMetric(Metric):
    def __init__(self):
        super().__init__()
        self.name = "Duration"

    def collect(self, start_time, end_time):
        duration = (end_time - start_time).total_seconds()
        return duration

    def store(self, metadata, value):
        metadata.duration = value


class ErrorMetric(Metric):
    def __init__(self):
        super().__init__()
        self.name = "Error"

    def collect(self, error_message):
        if error_message:
            return True
        else:
            return False

    def store(self, metadata, value):
        if value:
            metadata.status = 'failure'
            metadata.error_message = str(value)


class ETLOrchestrator:
    def __init__(self, csv_path=None, json_path=None, api_url=None):
        self.csv_extractor = CSVExtractor(csv_path) if csv_path else None
        self.json_extractor = JSONExtractor(json_path) if json_path else None
        self.api_extractor = RESTAPIExtractor(api_url) if api_url else None
        self.metadata = PipelineRunMetadata()

    def run(self):
        logger.info("ETL process started")

        # Increment the total number of runs
        run_count.inc()

        self.metadata.start()

        data_sources = []

        if self.csv_extractor:
            try:
                new_data = self.csv_extractor.extract_new_data()
                if not new_data.empty:
                    data_sources.append(('CSV', new_data))
                    self.metadata.log_data_source('CSV', {'file_path': self.csv_extractor.file_path})
            except Exception as e:
                logger.error(f"Failed to extract CSV: {e}")

        if self.json_extractor:
            try:
                new_data = self.json_extractor.extract_new_data()
                if new_data is not None:
                    data_sources.append(('JSON', new_data))
                    self.metadata.log_data_source('JSON', {'file_path': self.json_extractor.file_path})
            except Exception as e:
                logger.error(f"Failed to extract JSON: {e}")

        if self.api_extractor:
            try:
                new_data = self.api_extractor.extract_new_data()
                if new_data is not None:
                    data_sources.append(('API', new_data))
                    self.metadata.log_data_source('API', {'url': self.api_extractor.url})
            except Exception as e:
                logger.error(f"Failed to fetch API data: {e}")

        transformer = DataTransformer()

        transformed_data = []
        for source, data in data_sources:
            try:
                df = pd.DataFrame(transformer.transform(data))
                transformed_data.append(df)
            except Exception as e:
                logger.error(f"Transformation failed for {source}: {e}")

        loader = DataLoader(db_path='data.db')
        try:
            if transformed_data:
                start_time = datetime.now()
                loader.load(pd.concat(transformed_data))
                end_time = datetime.now()

                # Record the duration of the job
                job_duration_summary.observe((end_time - start_time).total_seconds())

        except Exception as e:
            self.metadata.end(success=False, error_message=str(e))
            logger.error(f"Loading data to database failed: {e}")
            return

        # Collect and store metrics
        row_count_metric = RowCountMetric()
        duration_metric = DurationMetric()
        error_metric = ErrorMetric()

        try:
            row_count_value = row_count_metric.collect(data_sources)
            row_count_metric.store(self.metadata, row_count_value)

            self.metadata.end(success=True, error_message=None)
            success_run_count.inc()  # Increment successful runs
        except Exception as e:
            error_metric.store(self.metadata, str(e))
            self.metadata.end(success=False, error_message=str(e))

        # Store metadata
        self.metadata.save_to_file('pipeline_run_metadata.json')

        logger.info("ETL process completed")
```

